public boolean canSortUsingSwap(int[] nums) {
    for (int i = 1; i < nums.length; i++) {
        if (nums[i] < nums[i - 1]) {
            int temp = nums[i];
            nums[i] = nums[i - 1];
            nums[i - 1] = temp;
            if (isSorted(nums)) {
                return true;
            }
            temp = nums[i];
            nums[i] = nums[i - 1];
            nums[i - 1] = temp;
        }
    }
    return false;
}

private boolean isSorted(int[] nums) {
    for (int i = 1; i < nums.length; i++) {
        if (nums[i] < nums[i - 1]) {
            return false;
        }
    }
    return true;
}
```

